server_scripts { 'server.lua' }

dependencies { 'qbx_core', 'ox_lib' }

files.config.lua:
Config = {}
Config.Shop = vector3(-56.7, -1096.7, 26.4)
Config.Vehicles = {
    { model = 'blista', price = 8000, label = 'Blista' },
    { model = 'asea', price = 5000, label = 'Asea' },
}

files.client.lua:
RegisterCommand('vehshop', function()
    local options = {}
    for _, v in ipairs(Config.Vehicles) do
        options[#options+1] = {
            title = v.label,
            description = ('$%s'):format(v.price),
            onSelect = function()
                TriggerServerEvent('qbox-vehicleshop:server:buy', v.model, v.price)
            end,
        }
    end
    lib.registerContext({ id = 'vehshop', title = 'Concession', options = options })
    lib.showContext('vehshop')
end)
